  let opensearchService: OpensearchService;
  let testIndexName: string;

  beforeAll(async () => {
    // Initialize real OpenSearch service
    // Global cleanup: delete all e2e_test_* indices
  });

  beforeEach(() => {
    testIndexName = generateTestIndexName();
  });

  afterEach(async () => {
    // Delete test index
  });

  describe('Health & Cluster', () => {
    it('should check cluster health');
    it('should configure ML settings');
  });

  describe('Index Management', () => {
    it('should create index with knn settings');
    it('should delete index');
    it('should check index exists');
  });

  describe('Bulk Indexing', () => {
    it('should bulk index products');
    it('should handle bulk errors gracefully');
  });

  describe('Search (Non-Neural)', () => {
    it('should search with match query');
    it('should search with bool filters');
  });

  describe('Pipeline Management', () => {
    it('should create ingest pipeline (no model)');
    it('should create search pipeline');
    it('should delete pipelines');
  });
});
```

#### Tier 2: Neural Search Integration Test (Separate, Optional)
**Scope**: Full bootstrap with ML model (SKIPPED by default in CI)

**Test Structure**:
```typescript
// test/opensearch/opensearch-neural-bootstrap.e2e-spec.ts (NEW, SKIPPED)
describe.skip('OpensearchNeuralService - Full Bootstrap (e2e)', () => {
  // Only run manually: npm run test:e2e -- opensearch-neural-bootstrap
  // Tests full model deployment + neural search
  // Expected runtime: 60-90 seconds
});
```

**Rationale**:
- Separates fast tests (run every commit) from slow tests (run on-demand)
- Keeps CI pipeline fast (<5 min)
- Still tests 95% of OpenSearch functionality
- Full bootstrap can be tested locally or in special CI job

